25	/// A pointer to a packet.
26	pub(crate) struct ZeroToken(*mut ());
27	
28	impl Default for ZeroToken {
29	    fn default() -> Self {
30	        Self(ptr::null_mut())
31	    }
32	}
33	
34	impl fmt::Debug for ZeroToken {
35	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
36	        fmt::Debug::fmt(&(self.0 as usize), f)
37	    }
