40	/// A slot for passing one message from a sender to a receiver.
41	struct Packet<T> {
42	    /// Equals `true` if the packet is allocated on the stack.
43	    on_stack: bool,
44	
45	    /// Equals `true` once the packet is ready for reading or writing.
46	    ready: AtomicBool,
47	
48	    /// The message.
49	    msg: UnsafeCell<Option<T>>,
50	}
51	
52	impl<T> Packet<T> {
53	    /// Creates an empty packet on the stack.
54	    fn empty_on_stack() -> Self {
55	        Self {
56	            on_stack: true,
57	            ready: AtomicBool::new(false),
58	            msg: UnsafeCell::new(None),
59	        }
60	    }
61	
62	    /// Creates an empty packet on the heap.
63	    fn empty_on_heap() -> Box<Self> {
64	        Box::new(Self {
65	            on_stack: false,
66	            ready: AtomicBool::new(false),
67	            msg: UnsafeCell::new(None),
68	        })
69	    }
70	
71	    /// Creates a packet on the stack, containing a message.
72	    fn message_on_stack(msg: T) -> Self {
73	        Self {
74	            on_stack: true,
75	            ready: AtomicBool::new(false),
76	            msg: UnsafeCell::new(Some(msg)),
77	        }
78	    }
79	
80	    /// Waits until the packet becomes ready for reading or writing.
81	    fn wait_ready(&self) {
82	        let backoff = Backoff::new();
83	        while !self.ready.load(Ordering::Acquire) {
84	            backoff.snooze();
85	        }
86	    }
87	}
88	
89	/// Inner representation of a zero-capacity channel.
90	struct Inner {
91	    /// Senders waiting to pair up with a receive operation.
92	    senders: Waker,
93	
94	    /// Receivers waiting to pair up with a send operation.
95	    receivers: Waker,
96	
97	    /// Equals `true` when the channel is disconnected.
98	    is_disconnected: bool,
99	}
100	
101	/// Zero-capacity channel.
102	pub(crate) struct Channel<T> {
103	    /// Inner representation of the channel.
104	    inner: Mutex<Inner>,
105	
106	    /// Indicates that dropping a `Channel<T>` may drop values of type `T`.
107	    _marker: PhantomData<T>,
108	}
109	
110	impl<T> Channel<T> {
111	    /// Constructs a new zero-capacity channel.
112	    pub(crate) fn new() -> Self {
113	        Self {
114	            inner: Mutex::new(Inner {
115	                senders: Waker::new(),
116	                receivers: Waker::new(),
117	                is_disconnected: false,
118	            }),
119	            _marker: PhantomData,
120	        }
121	    }
122	
123	    /// Returns a receiver handle to the channel.
124	    pub(crate) fn receiver(&self) -> Receiver<'_, T> {
125	        Receiver(self)
126	    }
127	
128	    /// Returns a sender handle to the channel.
129	    pub(crate) fn sender(&self) -> Sender<'_, T> {
130	        Sender(self)
131	    }
132	
133	    /// Attempts to reserve a slot for sending a message.
134	    fn start_send(&self, token: &mut Token) -> bool {
135	        let mut inner = self.inner.lock();
136	
137	        // If there's a waiting receiver, pair up with it.
138	        if let Some(operation) = inner.receivers.try_select() {
139	            token.zero.0 = operation.packet;
140	            true
141	        } else if inner.is_disconnected {
142	            token.zero.0 = ptr::null_mut();
143	            true
144	        } else {
145	            false
146	        }
147	    }
148	
149	    /// Writes a message into the packet.
150	    pub(crate) unsafe fn write(&self, token: &mut Token, msg: T) -> Result<(), T> {
151	        // If there is no packet, the channel is disconnected.
152	        if token.zero.0.is_null() {
153	            return Err(msg);
154	        }
155	
156	        let packet = unsafe { &*(token.zero.0 as *const Packet<T>) };
157	        unsafe { packet.msg.get().write(Some(msg)) }
158	        packet.ready.store(true, Ordering::Release);
159	        Ok(())
160	    }
161	
162	    /// Attempts to pair up with a sender.
163	    fn start_recv(&self, token: &mut Token) -> bool {
164	        let mut inner = self.inner.lock();
165	
166	        // If there's a waiting sender, pair up with it.
167	        if let Some(operation) = inner.senders.try_select() {
168	            token.zero.0 = operation.packet;
169	            true
170	        } else if inner.is_disconnected {
171	            token.zero.0 = ptr::null_mut();
172	            true
173	        } else {
174	            false
175	        }
176	    }
177	
178	    /// Reads a message from the packet.
179	    pub(crate) unsafe fn read(&self, token: &mut Token) -> Result<T, ()> {
180	        // If there is no packet, the channel is disconnected.
181	        if token.zero.0.is_null() {
182	            return Err(());
183	        }
184	
185	        let packet = unsafe { &*(token.zero.0 as *const Packet<T>) };
186	
187	        if packet.on_stack {
188	            // The message has been in the packet from the beginning, so there is no need to wait
189	            // for it. However, after reading the message, we need to set `ready` to `true` in
190	            // order to signal that the packet can be destroyed.
191	            let msg = unsafe { packet.msg.get().replace(None).unwrap() };
192	            packet.ready.store(true, Ordering::Release);
193	            Ok(msg)
194	        } else {
195	            // Wait until the message becomes available, then read it and destroy the
196	            // heap-allocated packet.
197	            packet.wait_ready();
198	            let msg = unsafe { packet.msg.get().replace(None).unwrap() };
199	            drop(unsafe { Box::from_raw(token.zero.0.cast::<Packet<T>>()) });
200	            Ok(msg)
201	        }
202	    }
203	
204	    /// Attempts to send a message into the channel.
205	    pub(crate) fn try_send(&self, msg: T) -> Result<(), TrySendError<T>> {
206	        let token = &mut Token::default();
207	        let mut inner = self.inner.lock();
208	
209	        // If there's a waiting receiver, pair up with it.
210	        if let Some(operation) = inner.receivers.try_select() {
211	            token.zero.0 = operation.packet;
212	            drop(inner);
213	            unsafe {
214	                self.write(token, msg).ok().unwrap();
215	            }
216	            Ok(())
217	        } else if inner.is_disconnected {
218	            Err(TrySendError::Disconnected(msg))
219	        } else {
220	            Err(TrySendError::Full(msg))
221	        }
222	    }
223	
224	    /// Sends a message into the channel.
225	    pub(crate) fn send(
226	        &self,
227	        msg: T,
228	        deadline: Option<Instant>,
229	    ) -> Result<(), SendTimeoutError<T>> {
230	        let token = &mut Token::default();
231	        let mut inner = self.inner.lock();
232	
233	        // If there's a waiting receiver, pair up with it.
234	        if let Some(operation) = inner.receivers.try_select() {
235	            token.zero.0 = operation.packet;
236	            drop(inner);
237	            unsafe {
238	                self.write(token, msg).ok().unwrap();
239	            }
240	            return Ok(());
241	        }
242	
243	        if inner.is_disconnected {
244	            return Err(SendTimeoutError::Disconnected(msg));
245	        }
246	
247	        Context::with(|cx| {
248	            // Prepare for blocking until a receiver wakes us up.
249	            let oper = Operation::hook(token);
250	            let mut packet = Packet::<T>::message_on_stack(msg);
251	            inner
252	                .senders
253	                .register_with_packet(oper, &mut packet as *mut Packet<T> as *mut (), cx);
254	            inner.receivers.notify();
255	            drop(inner);
256	
257	            // Block the current thread.
258	            let sel = cx.wait_until(deadline);
259	
260	            match sel {
261	                Selected::Waiting => unreachable!(),
262	                Selected::Aborted => {
263	                    self.inner.lock().senders.unregister(oper).unwrap();
264	                    let msg = unsafe { packet.msg.get().replace(None).unwrap() };
265	                    Err(SendTimeoutError::Timeout(msg))
266	                }
267	                Selected::Disconnected => {
268	                    self.inner.lock().senders.unregister(oper).unwrap();
269	                    let msg = unsafe { packet.msg.get().replace(None).unwrap() };
270	                    Err(SendTimeoutError::Disconnected(msg))
271	                }
272	                Selected::Operation(_) => {
273	                    // Wait until the message is read, then drop the packet.
274	                    packet.wait_ready();
275	                    Ok(())
276	                }
277	            }
278	        })
279	    }
280	
281	    /// Attempts to receive a message without blocking.
282	    pub(crate) fn try_recv(&self) -> Result<T, TryRecvError> {
283	        let token = &mut Token::default();
284	        let mut inner = self.inner.lock();
285	
286	        // If there's a waiting sender, pair up with it.
287	        if let Some(operation) = inner.senders.try_select() {
288	            token.zero.0 = operation.packet;
289	            drop(inner);
290	            unsafe { self.read(token).map_err(|_| TryRecvError::Disconnected) }
291	        } else if inner.is_disconnected {
292	            Err(TryRecvError::Disconnected)
293	        } else {
294	            Err(TryRecvError::Empty)
295	        }
296	    }
297	
298	    /// Receives a message from the channel.
299	    pub(crate) fn recv(&self, deadline: Option<Instant>) -> Result<T, RecvTimeoutError> {
300	        let token = &mut Token::default();
301	        let mut inner = self.inner.lock();
302	
303	        // If there's a waiting sender, pair up with it.
304	        if let Some(operation) = inner.senders.try_select() {
305	            token.zero.0 = operation.packet;
306	            drop(inner);
307	            unsafe {
308	                return self.read(token).map_err(|_| RecvTimeoutError::Disconnected);
309	            }
310	        }
311	
312	        if inner.is_disconnected {
313	            return Err(RecvTimeoutError::Disconnected);
314	        }
315	
316	        Context::with(|cx| {
317	            // Prepare for blocking until a sender wakes us up.
318	            let oper = Operation::hook(token);
319	            let mut packet = Packet::<T>::empty_on_stack();
320	            inner.receivers.register_with_packet(
321	                oper,
322	                &mut packet as *mut Packet<T> as *mut (),
323	                cx,
324	            );
325	            inner.senders.notify();
326	            drop(inner);
327	
328	            // Block the current thread.
329	            let sel = cx.wait_until(deadline);
330	
331	            match sel {
332	                Selected::Waiting => unreachable!(),
333	                Selected::Aborted => {
334	                    self.inner.lock().receivers.unregister(oper).unwrap();
335	                    Err(RecvTimeoutError::Timeout)
336	                }
337	                Selected::Disconnected => {
338	                    self.inner.lock().receivers.unregister(oper).unwrap();
339	                    Err(RecvTimeoutError::Disconnected)
340	                }
341	                Selected::Operation(_) => {
342	                    // Wait until the message is provided, then read it.
343	                    packet.wait_ready();
344	                    unsafe { Ok(packet.msg.get().replace(None).unwrap()) }
345	                }
346	            }
347	        })
348	    }
349	
350	    /// Disconnects the channel and wakes up all blocked senders and receivers.
351	    ///
352	    /// Returns `true` if this call disconnected the channel.
353	    pub(crate) fn disconnect(&self) -> bool {
354	        let mut inner = self.inner.lock();
355	
356	        if !inner.is_disconnected {
357	            inner.is_disconnected = true;
358	            inner.senders.disconnect();
359	            inner.receivers.disconnect();
360	            true
361	        } else {
362	            false
363	        }
364	    }
365	
366	    /// Returns the current number of messages inside the channel.
367	    pub(crate) fn len(&self) -> usize {
368	        0
369	    }
370	
371	    /// Returns the capacity of the channel.
372	    pub(crate) fn capacity(&self) -> Option<usize> {
373	        Some(0)
374	    }
375	
376	    /// Returns `true` if the channel is empty.
377	    pub(crate) fn is_empty(&self) -> bool {
378	        true
379	    }
380	
381	    /// Returns `true` if the channel is full.
382	    pub(crate) fn is_full(&self) -> bool {
383	        true
384	    }
385	}
386	
387	/// Receiver handle to a channel.
388	pub(crate) struct Receiver<'a, T>(&'a Channel<T>);
389	
390	/// Sender handle to a channel.
391	pub(crate) struct Sender<'a, T>(&'a Channel<T>);
392	
393	impl<T> SelectHandle for Receiver<'_, T> {
394	    fn try_select(&self, token: &mut Token) -> bool {
395	        self.0.start_recv(token)
396	    }
397	
398	    fn deadline(&self) -> Option<Instant> {
399	        None
400	    }
401	
402	    fn register(&self, oper: Operation, cx: &Context) -> bool {
403	        let packet = Box::into_raw(Packet::<T>::empty_on_heap());
404	
405	        let mut inner = self.0.inner.lock();
406	        inner
407	            .receivers
408	            .register_with_packet(oper, packet.cast::<()>(), cx);
409	        inner.senders.notify();
410	        inner.senders.can_select() || inner.is_disconnected
411	    }
412	
413	    fn unregister(&self, oper: Operation) {
414	        if let Some(operation) = self.0.inner.lock().receivers.unregister(oper) {
415	            unsafe {
416	                drop(Box::from_raw(operation.packet.cast::<Packet<T>>()));
417	            }
418	        }
419	    }
420	
421	    fn accept(&self, token: &mut Token, cx: &Context) -> bool {
422	        token.zero.0 = cx.wait_packet();
423	        true
424	    }
425	
426	    fn is_ready(&self) -> bool {
427	        let inner = self.0.inner.lock();
428	        inner.senders.can_select() || inner.is_disconnected
429	    }
430	
431	    fn watch(&self, oper: Operation, cx: &Context) -> bool {
432	        let mut inner = self.0.inner.lock();
