347	/// The sending side of a channel.
348	///
349	/// # Examples
350	///
351	/// ```
352	/// use std::thread;
353	/// use crossbeam_channel::unbounded;
354	///
355	/// let (s1, r) = unbounded();
356	/// let s2 = s1.clone();
357	///
358	/// thread::spawn(move || s1.send(1).unwrap());
359	/// thread::spawn(move || s2.send(2).unwrap());
360	///
361	/// let msg1 = r.recv().unwrap();
362	/// let msg2 = r.recv().unwrap();
363	///
364	/// assert_eq!(msg1 + msg2, 3);
365	/// ```
366	pub struct Sender<T> {
367	    flavor: SenderFlavor<T>,
368	}
369	
370	/// Sender flavors.
371	enum SenderFlavor<T> {
372	    /// Bounded channel based on a preallocated array.
373	    Array(counter::Sender<flavors::array::Channel<T>>),
374	
375	    /// Unbounded channel implemented as a linked list.
376	    List(counter::Sender<flavors::list::Channel<T>>),
377	
378	    /// Zero-capacity channel.
379	    Zero(counter::Sender<flavors::zero::Channel<T>>),
380	}
381	
382	unsafe impl<T: Send> Send for Sender<T> {}
383	unsafe impl<T: Send> Sync for Sender<T> {}
384	
385	impl<T> UnwindSafe for Sender<T> {}
386	impl<T> RefUnwindSafe for Sender<T> {}
387	
388	impl<T> Sender<T> {
389	    /// Attempts to send a message into the channel without blocking.
390	    ///
391	    /// This method will either send a message into the channel immediately or return an error if
392	    /// the channel is full or disconnected. The returned error contains the original message.
393	    ///
394	    /// If called on a zero-capacity channel, this method will send the message only if there
395	    /// happens to be a receive operation on the other side of the channel at the same time.
396	    ///
397	    /// # Examples
398	    ///
399	    /// ```
400	    /// use crossbeam_channel::{bounded, TrySendError};
401	    ///
402	    /// let (s, r) = bounded(1);
403	    ///
404	    /// assert_eq!(s.try_send(1), Ok(()));
405	    /// assert_eq!(s.try_send(2), Err(TrySendError::Full(2)));
406	    ///
407	    /// drop(r);
408	    /// assert_eq!(s.try_send(3), Err(TrySendError::Disconnected(3)));
409	    /// ```
410	    pub fn try_send(&self, msg: T) -> Result<(), TrySendError<T>> {
411	        match &self.flavor {
412	            SenderFlavor::Array(chan) => chan.try_send(msg),
413	            SenderFlavor::List(chan) => chan.try_send(msg),
414	            SenderFlavor::Zero(chan) => chan.try_send(msg),
415	        }
416	    }
417	
418	    /// Blocks the current thread until a message is sent or the channel is disconnected.
419	    ///
420	    /// If the channel is full and not disconnected, this call will block until the send operation
421	    /// can proceed. If the channel becomes disconnected, this call will wake up and return an
422	    /// error. The returned error contains the original message.
423	    ///
424	    /// If called on a zero-capacity channel, this method will wait for a receive operation to
425	    /// appear on the other side of the channel.
426	    ///
427	    /// # Examples
428	    ///
429	    /// ```
430	    /// use std::thread;
431	    /// use std::time::Duration;
432	    /// use crossbeam_channel::{bounded, SendError};
433	    ///
434	    /// let (s, r) = bounded(1);
435	    /// assert_eq!(s.send(1), Ok(()));
436	    ///
437	    /// thread::spawn(move || {
438	    ///     assert_eq!(r.recv(), Ok(1));
439	    ///     thread::sleep(Duration::from_secs(1));
440	    ///     drop(r);
441	    /// });
442	    ///
443	    /// assert_eq!(s.send(2), Ok(()));
444	    /// assert_eq!(s.send(3), Err(SendError(3)));
445	    /// ```
446	    pub fn send(&self, msg: T) -> Result<(), SendError<T>> {
447	        match &self.flavor {
448	            SenderFlavor::Array(chan) => chan.send(msg, None),
449	            SenderFlavor::List(chan) => chan.send(msg, None),
450	            SenderFlavor::Zero(chan) => chan.send(msg, None),
451	        }
452	        .map_err(|err| match err {
453	            SendTimeoutError::Disconnected(msg) => SendError(msg),
454	            SendTimeoutError::Timeout(_) => unreachable!(),
455	        })
456	    }
457	
458	    /// Waits for a message to be sent into the channel, but only for a limited time.
459	    ///
460	    /// If the channel is full and not disconnected, this call will block until the send operation
461	    /// can proceed or the operation times out. If the channel becomes disconnected, this call will
462	    /// wake up and return an error. The returned error contains the original message.
463	    ///
464	    /// If called on a zero-capacity channel, this method will wait for a receive operation to
465	    /// appear on the other side of the channel.
466	    ///
467	    /// # Examples
468	    ///
469	    /// ```
470	    /// use std::thread;
471	    /// use std::time::Duration;
472	    /// use crossbeam_channel::{bounded, SendTimeoutError};
473	    ///
474	    /// let (s, r) = bounded(0);
475	    ///
476	    /// thread::spawn(move || {
477	    ///     thread::sleep(Duration::from_secs(1));
478	    ///     assert_eq!(r.recv(), Ok(2));
479	    ///     drop(r);
480	    /// });
481	    ///
482	    /// assert_eq!(
483	    ///     s.send_timeout(1, Duration::from_millis(500)),
484	    ///     Err(SendTimeoutError::Timeout(1)),
485	    /// );
486	    /// assert_eq!(
487	    ///     s.send_timeout(2, Duration::from_secs(1)),
488	    ///     Ok(()),
489	    /// );
490	    /// assert_eq!(
491	    ///     s.send_timeout(3, Duration::from_millis(500)),
492	    ///     Err(SendTimeoutError::Disconnected(3)),
493	    /// );
494	    /// ```
495	    pub fn send_timeout(&self, msg: T, timeout: Duration) -> Result<(), SendTimeoutError<T>> {
496	        match Instant::now().checked_add(timeout) {
497	            Some(deadline) => self.send_deadline(msg, deadline),
498	            None => self.send(msg).map_err(SendTimeoutError::from),
499	        }
500	    }
501	
502	    /// Waits for a message to be sent into the channel, but only until a given deadline.
503	    ///
504	    /// If the channel is full and not disconnected, this call will block until the send operation
505	    /// can proceed or the operation times out. If the channel becomes disconnected, this call will
506	    /// wake up and return an error. The returned error contains the original message.
507	    ///
508	    /// If called on a zero-capacity channel, this method will wait for a receive operation to
509	    /// appear on the other side of the channel.
510	    ///
511	    /// # Examples
512	    ///
513	    /// ```
514	    /// use std::thread;
515	    /// use std::time::{Duration, Instant};
516	    /// use crossbeam_channel::{bounded, SendTimeoutError};
517	    ///
518	    /// let (s, r) = bounded(0);
519	    ///
520	    /// thread::spawn(move || {
521	    ///     thread::sleep(Duration::from_secs(1));
522	    ///     assert_eq!(r.recv(), Ok(2));
523	    ///     drop(r);
524	    /// });
525	    ///
526	    /// let now = Instant::now();
527	    ///
528	    /// assert_eq!(
529	    ///     s.send_deadline(1, now + Duration::from_millis(500)),
530	    ///     Err(SendTimeoutError::Timeout(1)),
531	    /// );
532	    /// assert_eq!(
533	    ///     s.send_deadline(2, now + Duration::from_millis(1500)),
534	    ///     Ok(()),
535	    /// );
536	    /// assert_eq!(
537	    ///     s.send_deadline(3, now + Duration::from_millis(2000)),
538	    ///     Err(SendTimeoutError::Disconnected(3)),
539	    /// );
540	    /// ```
541	    pub fn send_deadline(&self, msg: T, deadline: Instant) -> Result<(), SendTimeoutError<T>> {
542	        match &self.flavor {
543	            SenderFlavor::Array(chan) => chan.send(msg, Some(deadline)),
544	            SenderFlavor::List(chan) => chan.send(msg, Some(deadline)),
545	            SenderFlavor::Zero(chan) => chan.send(msg, Some(deadline)),
546	        }
547	    }
548	
549	    /// Returns `true` if the channel is empty.
550	    ///
551	    /// Note: Zero-capacity channels are always empty.
552	    ///
553	    /// # Examples
554	    ///
555	    /// ```
556	    /// use crossbeam_channel::unbounded;
557	    ///
558	    /// let (s, r) = unbounded();
559	    /// assert!(s.is_empty());
560	    ///
561	    /// s.send(0).unwrap();
562	    /// assert!(!s.is_empty());
563	    /// ```
564	    pub fn is_empty(&self) -> bool {
565	        match &self.flavor {
566	            SenderFlavor::Array(chan) => chan.is_empty(),
567	            SenderFlavor::List(chan) => chan.is_empty(),
568	            SenderFlavor::Zero(chan) => chan.is_empty(),
569	        }
570	    }
571	
572	    /// Returns `true` if the channel is full.
573	    ///
574	    /// Note: Zero-capacity channels are always full.
575	    ///
576	    /// # Examples
577	    ///
578	    /// ```
579	    /// use crossbeam_channel::bounded;
580	    ///
581	    /// let (s, r) = bounded(1);
582	    ///
583	    /// assert!(!s.is_full());
584	    /// s.send(0).unwrap();
585	    /// assert!(s.is_full());
586	    /// ```
587	    pub fn is_full(&self) -> bool {
588	        match &self.flavor {
589	            SenderFlavor::Array(chan) => chan.is_full(),
590	            SenderFlavor::List(chan) => chan.is_full(),
591	            SenderFlavor::Zero(chan) => chan.is_full(),
592	        }
593	    }
594	
595	    /// Returns the number of messages in the channel.
596	    ///
597	    /// # Examples
598	    ///
599	    /// ```
600	    /// use crossbeam_channel::unbounded;
601	    ///
602	    /// let (s, r) = unbounded();
603	    /// assert_eq!(s.len(), 0);
604	    ///
605	    /// s.send(1).unwrap();
606	    /// s.send(2).unwrap();
607	    /// assert_eq!(s.len(), 2);
608	    /// ```
609	    pub fn len(&self) -> usize {
610	        match &self.flavor {
611	            SenderFlavor::Array(chan) => chan.len(),
612	            SenderFlavor::List(chan) => chan.len(),
613	            SenderFlavor::Zero(chan) => chan.len(),
614	        }
615	    }
616	
617	    /// If the channel is bounded, returns its capacity.
618	    ///
619	    /// # Examples
620	    ///
621	    /// ```
622	    /// use crossbeam_channel::{bounded, unbounded};
623	    ///
624	    /// let (s, _) = unbounded::<i32>();
625	    /// assert_eq!(s.capacity(), None);
626	    ///
627	    /// let (s, _) = bounded::<i32>(5);
628	    /// assert_eq!(s.capacity(), Some(5));
629	    ///
630	    /// let (s, _) = bounded::<i32>(0);
631	    /// assert_eq!(s.capacity(), Some(0));
632	    /// ```
633	    pub fn capacity(&self) -> Option<usize> {
634	        match &self.flavor {
635	            SenderFlavor::Array(chan) => chan.capacity(),
636	            SenderFlavor::List(chan) => chan.capacity(),
637	            SenderFlavor::Zero(chan) => chan.capacity(),
638	        }
639	    }
640	
641	    /// Returns `true` if senders belong to the same channel.
642	    ///
643	    /// # Examples
644	    ///
645	    /// ```rust
646	    /// use crossbeam_channel::unbounded;
647	    ///
648	    /// let (s, _) = unbounded::<usize>();
649	    ///
650	    /// let s2 = s.clone();
651	    /// assert!(s.same_channel(&s2));
652	    ///
653	    /// let (s3, _) = unbounded();
654	    /// assert!(!s.same_channel(&s3));
655	    /// ```
656	    pub fn same_channel(&self, other: &Self) -> bool {
657	        match (&self.flavor, &other.flavor) {
658	            (SenderFlavor::Array(ref a), SenderFlavor::Array(ref b)) => a == b,
659	            (SenderFlavor::List(ref a), SenderFlavor::List(ref b)) => a == b,
660	            (SenderFlavor::Zero(ref a), SenderFlavor::Zero(ref b)) => a == b,
661	            _ => false,
662	        }
