60	/// Channel that delivers messages periodically.
61	pub(crate) struct Channel {
62	    /// The instant at which the next message will be delivered.
63	    delivery_time: AtomicCell<Align<Instant>>,
64	
65	    /// The time interval in which messages get delivered.
66	    duration: Duration,
67	}
68	
69	impl Channel {
70	    /// Creates a channel that delivers messages periodically.
71	    #[inline]
72	    pub(crate) fn new(delivery_time: Instant, dur: Duration) -> Self {
73	        Self {
74	            delivery_time: AtomicCell::new(Align(delivery_time)),
75	            duration: dur,
76	        }
77	    }
78	
79	    /// Attempts to receive a message without blocking.
80	    #[inline]
81	    pub(crate) fn try_recv(&self) -> Result<Instant, TryRecvError> {
82	        loop {
83	            let now = Instant::now();
84	            let delivery_time = self.delivery_time.load();
85	
86	            if now < delivery_time.0 {
87	                return Err(TryRecvError::Empty);
88	            }
89	
90	            if self
91	                .delivery_time
92	                .compare_exchange(delivery_time, Align(now + self.duration))
93	                .is_ok()
94	            {
95	                return Ok(delivery_time.0);
96	            }
97	        }
98	    }
99	
100	    /// Receives a message from the channel.
101	    #[inline]
102	    pub(crate) fn recv(&self, deadline: Option<Instant>) -> Result<Instant, RecvTimeoutError> {
103	        loop {
104	            let delivery_time = self.delivery_time.load();
105	            let now = Instant::now();
106	
107	            if let Some(d) = deadline {
108	                if d < delivery_time.0 {
109	                    if now < d {
110	                        thread::sleep(d - now);
111	                    }
112	                    return Err(RecvTimeoutError::Timeout);
113	                }
114	            }
115	
116	            if self
117	                .delivery_time
118	                .compare_exchange(
119	                    delivery_time,
120	                    Align(delivery_time.0.max(now) + self.duration),
121	                )
122	                .is_ok()
123	            {
124	                if now < delivery_time.0 {
125	                    thread::sleep(delivery_time.0 - now);
126	                }
127	                return Ok(delivery_time.0);
128	            }
129	        }
130	    }
131	
132	    /// Reads a message from the channel.
133	    #[inline]
134	    pub(crate) unsafe fn read(&self, token: &mut Token) -> Result<Instant, ()> {
135	        token.tick.ok_or(())
136	    }
137	
138	    /// Returns `true` if the channel is empty.
139	    #[inline]
140	    pub(crate) fn is_empty(&self) -> bool {
141	        Instant::now() < self.delivery_time.load().0
142	    }
143	
144	    /// Returns `true` if the channel is full.
145	    #[inline]
146	    pub(crate) fn is_full(&self) -> bool {
147	        !self.is_empty()
148	    }
149	
150	    /// Returns the number of messages in the channel.
151	    #[inline]
152	    pub(crate) fn len(&self) -> usize {
153	        usize::from(!self.is_empty())
154	    }
155	
156	    /// Returns the capacity of the channel.
157	    #[inline]
158	    pub(crate) fn capacity(&self) -> Option<usize> {
159	        Some(1)
160	    }
161	}
162	
163	impl SelectHandle for Channel {
164	    #[inline]
165	    fn try_select(&self, token: &mut Token) -> bool {
166	        match self.try_recv() {
167	            Ok(msg) => {
168	                token.tick = Some(msg);
169	                true
170	            }
171	            Err(TryRecvError::Disconnected) => {
172	                token.tick = None;
173	                true
174	            }
175	            Err(TryRecvError::Empty) => false,
176	        }
177	    }
178	
179	    #[inline]
180	    fn deadline(&self) -> Option<Instant> {
181	        Some(self.delivery_time.load().0)
182	    }
183	
184	    #[inline]
185	    fn register(&self, _oper: Operation, _cx: &Context) -> bool {
186	        self.is_ready()
187	    }
188	
189	    #[inline]
190	    fn unregister(&self, _oper: Operation) {}
191	
192	    #[inline]
193	    fn accept(&self, token: &mut Token, _cx: &Context) -> bool {
194	        self.try_select(token)
195	    }
196	
197	    #[inline]
198	    fn is_ready(&self) -> bool {
199	        !self.is_empty()
200	    }
201	
202	    #[inline]
203	    fn watch(&self, _oper: Operation, _cx: &Context) -> bool {
204	        self.is_ready()
205	    }
206	
207	    #[inline]
208	    fn unwatch(&self, _oper: Operation) {}
209	}
