1	//! Waking mechanism for threads blocked on channel operations.
2	
3	use alloc::vec::Vec;
4	use core::{
5	    ptr,
6	    sync::atomic::{AtomicBool, Ordering},
7	};
8	use std::thread::{self, ThreadId};
9	
10	use crate::{
11	    context::Context,
12	    select::{Operation, Selected},
13	    utils::Mutex,
14	};
15	
16	/// Represents a thread blocked on a specific channel operation.
17	pub(crate) struct Entry {
18	    /// The operation.
19	    pub(crate) oper: Operation,
20	
21	    /// Optional packet.
22	    pub(crate) packet: *mut (),
23	
24	    /// Context associated with the thread owning this operation.
25	    pub(crate) cx: Context,
26	}
27	
28	/// A queue of threads blocked on channel operations.
29	///
30	/// This data structure is used by threads to register blocking operations and get woken up once
31	/// an operation becomes ready.
32	pub(crate) struct Waker {
33	    /// A list of select operations.
34	    selectors: Vec<Entry>,
35	
36	    /// A list of operations waiting to be ready.
37	    observers: Vec<Entry>,
38	}
39	
40	impl Waker {
41	    /// Creates a new `Waker`.
42	    #[inline]
43	    pub(crate) fn new() -> Self {
44	        Self {
45	            selectors: Vec::new(),
46	            observers: Vec::new(),
47	        }
48	    }
49	
50	    /// Registers a select operation.
51	    #[inline]
52	    pub(crate) fn register(&mut self, oper: Operation, cx: &Context) {
53	        self.register_with_packet(oper, ptr::null_mut(), cx);
54	    }
55	
56	    /// Registers a select operation and a packet.
57	    #[inline]
58	    pub(crate) fn register_with_packet(&mut self, oper: Operation, packet: *mut (), cx: &Context) {
59	        self.selectors.push(Entry {
60	            oper,
61	            packet,
62	            cx: cx.clone(),
63	        });
64	    }
65	
66	    /// Unregisters a select operation.
67	    #[inline]
68	    pub(crate) fn unregister(&mut self, oper: Operation) -> Option<Entry> {
69	        if let Some((i, _)) = self
70	            .selectors
71	            .iter()
72	            .enumerate()
73	            .find(|&(_, entry)| entry.oper == oper)
74	        {
75	            let entry = self.selectors.remove(i);
76	            Some(entry)
77	        } else {
78	            None
79	        }
80	    }
81	
82	    /// Attempts to find another thread's entry, select the operation, and wake it up.
83	    #[inline]
84	    pub(crate) fn try_select(&mut self) -> Option<Entry> {
85	        if self.selectors.is_empty() {
86	            None
87	        } else {
88	            let thread_id = current_thread_id();
89	
90	            self.selectors
91	                .iter()
92	                .position(|selector| {
93	                    // Does the entry belong to a different thread?
94	                    selector.cx.thread_id() != thread_id
95	                        && selector // Try selecting this operation.
96	                            .cx
97	                            .try_select(Selected::Operation(selector.oper))
98	                            .is_ok()
99	                        && {
100	                            // Provide the packet.
101	                            selector.cx.store_packet(selector.packet);
102	                            // Wake the thread up.
103	                            selector.cx.unpark();
104	                            true
105	                        }
106	                })
107	                // Remove the entry from the queue to keep it clean and improve
108	                // performance.
109	                .map(|pos| self.selectors.remove(pos))
110	        }
111	    }
112	
113	    /// Returns `true` if there is an entry which can be selected by the current thread.
114	    #[inline]
115	    pub(crate) fn can_select(&self) -> bool {
116	        if self.selectors.is_empty() {
117	            false
118	        } else {
119	            let thread_id = current_thread_id();
120	
121	            self.selectors.iter().any(|entry| {
122	                entry.cx.thread_id() != thread_id && entry.cx.selected() == Selected::Waiting
123	            })
124	        }
125	    }
126	
127	    /// Registers an operation waiting to be ready.
128	    #[inline]
129	    pub(crate) fn watch(&mut self, oper: Operation, cx: &Context) {
130	        self.observers.push(Entry {
131	            oper,
132	            packet: ptr::null_mut(),
133	            cx: cx.clone(),
134	        });
135	    }
136	
137	    /// Unregisters an operation waiting to be ready.
138	    #[inline]
139	    pub(crate) fn unwatch(&mut self, oper: Operation) {
140	        self.observers.retain(|e| e.oper != oper);
141	    }
142	
143	    /// Notifies all operations waiting to be ready.
144	    #[inline]
145	    pub(crate) fn notify(&mut self) {
146	        for entry in self.observers.drain(..) {
147	            if entry.cx.try_select(Selected::Operation(entry.oper)).is_ok() {
148	                entry.cx.unpark();
149	            }
150	        }
151	    }
152	
153	    /// Notifies all registered operations that the channel is disconnected.
154	    #[inline]
155	    pub(crate) fn disconnect(&mut self) {
156	        for entry in self.selectors.iter() {
157	            if entry.cx.try_select(Selected::Disconnected).is_ok() {
158	                // Wake the thread up.
159	                //
160	                // Here we don't remove the entry from the queue. Registered threads must
161	                // unregister from the waker by themselves. They might also want to recover the
162	                // packet value and destroy it, if necessary.
163	                entry.cx.unpark();
164	            }
165	        }
166	
167	        self.notify();
168	    }
169	}
170	
171	impl Drop for Waker {
172	    #[inline]
173	    fn drop(&mut self) {
174	        debug_assert_eq!(self.selectors.len(), 0);
175	        debug_assert_eq!(self.observers.len(), 0);
176	    }
177	}
178	
179	/// A waker that can be shared among threads without locking.
180	///
181	/// This is a simple wrapper around `Waker` that internally uses a mutex for synchronization.
182	pub(crate) struct SyncWaker {
183	    /// The inner `Waker`.
184	    inner: Mutex<Waker>,
185	
186	    /// `true` if the waker is empty.
187	    is_empty: AtomicBool,
188	}
189	
190	impl SyncWaker {
191	    /// Creates a new `SyncWaker`.
192	    #[inline]
193	    pub(crate) fn new() -> Self {
194	        Self {
195	            inner: Mutex::new(Waker::new()),
196	            is_empty: AtomicBool::new(true),
197	        }
198	    }
199	
200	    /// Registers the current thread with an operation.
201	    #[inline]
202	    pub(crate) fn register(&self, oper: Operation, cx: &Context) {
203	        let mut inner = self.inner.lock();
204	        inner.register(oper, cx);
205	        self.is_empty.store(
206	            inner.selectors.is_empty() && inner.observers.is_empty(),
207	            Ordering::SeqCst,
208	        );
209	    }
210	
211	    /// Unregisters an operation previously registered by the current thread.
212	    #[inline]
213	    pub(crate) fn unregister(&self, oper: Operation) -> Option<Entry> {
214	        let mut inner = self.inner.lock();
215	        let entry = inner.unregister(oper);
216	        self.is_empty.store(
217	            inner.selectors.is_empty() && inner.observers.is_empty(),
218	            Ordering::SeqCst,
219	        );
220	        entry
221	    }
222	
223	    /// Attempts to find one thread (not the current one), select its operation, and wake it up.
224	    #[inline]
225	    pub(crate) fn notify(&self) {
226	        if !self.is_empty.load(Ordering::SeqCst) {
227	            let mut inner = self.inner.lock();
228	            if !self.is_empty.load(Ordering::SeqCst) {
229	                inner.try_select();
230	                inner.notify();
231	                self.is_empty.store(
232	                    inner.selectors.is_empty() && inner.observers.is_empty(),
233	                    Ordering::SeqCst,
234	                );
235	            }
236	        }
237	    }
238	
239	    /// Registers an operation waiting to be ready.
240	    #[inline]
241	    pub(crate) fn watch(&self, oper: Operation, cx: &Context) {
242	        let mut inner = self.inner.lock();
243	        inner.watch(oper, cx);
244	        self.is_empty.store(
245	            inner.selectors.is_empty() && inner.observers.is_empty(),
246	            Ordering::SeqCst,
247	        );
248	    }
249	
250	    /// Unregisters an operation waiting to be ready.
251	    #[inline]
252	    pub(crate) fn unwatch(&self, oper: Operation) {
253	        let mut inner = self.inner.lock();
254	        inner.unwatch(oper);
255	        self.is_empty.store(
256	            inner.selectors.is_empty() && inner.observers.is_empty(),
257	            Ordering::SeqCst,
258	        );
259	    }
260	
261	    /// Notifies all threads that the channel is disconnected.
262	    #[inline]
263	    pub(crate) fn disconnect(&self) {
264	        let mut inner = self.inner.lock();
265	        inner.disconnect();
266	        self.is_empty.store(
267	            inner.selectors.is_empty() && inner.observers.is_empty(),
268	            Ordering::SeqCst,
269	        );
270	    }
271	}
272	
273	impl Drop for SyncWaker {
274	    #[inline]
275	    fn drop(&mut self) {
276	        debug_assert!(self.is_empty.load(Ordering::SeqCst));
277	    }
278	}
279	
280	/// Returns the id of the current thread.
281	#[inline]
282	fn current_thread_id() -> ThreadId {
283	    std::thread_local! {
284	        /// Cached thread-local id.
285	        static THREAD_ID: ThreadId = thread::current().id();
286	    }
287	
288	    THREAD_ID
289	        .try_with(|id| *id)
290	        .unwrap_or_else(|_| thread::current().id())
291	}
