771	    /// Attempts to select one of the operations without blocking.
772	    ///
773	    /// If an operation is ready, it is selected and returned. If multiple operations are ready at
774	    /// the same time, a random one among them is selected. If none of the operations are ready, an
775	    /// error is returned.
776	    ///
777	    /// An operation is considered to be ready if it doesn't have to block. Note that it is ready
778	    /// even when it will simply return an error because the channel is disconnected.
779	    ///
780	    /// The selected operation must be completed with [`SelectedOperation::send`]
781	    /// or [`SelectedOperation::recv`].
782	    ///
783	    /// # Examples
784	    ///
785	    /// ```
786	    /// use crossbeam_channel::{unbounded, Select};
787	    ///
788	    /// let (s1, r1) = unbounded();
789	    /// let (s2, r2) = unbounded();
790	    ///
791	    /// s1.send(10).unwrap();
792	    /// s2.send(20).unwrap();
793	    ///
794	    /// let mut sel = Select::new();
795	    /// let oper1 = sel.recv(&r1);
796	    /// let oper2 = sel.recv(&r2);
797	    ///
798	    /// // Both operations are initially ready, so a random one will be executed.
799	    /// let oper = sel.try_select();
800	    /// match oper {
801	    ///     Err(_) => panic!("both operations should be ready"),
802	    ///     Ok(oper) => match oper.index() {
803	    ///         i if i == oper1 => assert_eq!(oper.recv(&r1), Ok(10)),
804	    ///         i if i == oper2 => assert_eq!(oper.recv(&r2), Ok(20)),
805	    ///         _ => unreachable!(),
806	    ///     }
807	    /// }
808	    /// ```
809	    pub fn try_select(&mut self) -> Result<SelectedOperation<'a>, TrySelectError> {
810	        try_select(&mut self.handles, self.biased)
811	    }
