813	    /// Blocks until one of the operations becomes ready and selects it.
814	    ///
815	    /// Once an operation becomes ready, it is selected and returned. If multiple operations are
816	    /// ready at the same time, a random one among them is selected.
817	    ///
818	    /// An operation is considered to be ready if it doesn't have to block. Note that it is ready
819	    /// even when it will simply return an error because the channel is disconnected.
820	    ///
821	    /// The selected operation must be completed with [`SelectedOperation::send`]
822	    /// or [`SelectedOperation::recv`].
823	    ///
824	    /// # Panics
825	    ///
826	    /// Panics if no operations have been added to `Select`.
827	    ///
828	    /// # Examples
829	    ///
830	    /// ```
831	    /// use std::thread;
832	    /// use std::time::Duration;
833	    /// use crossbeam_channel::{unbounded, Select};
834	    ///
835	    /// let (s1, r1) = unbounded();
836	    /// let (s2, r2) = unbounded();
837	    ///
838	    /// # let t1 =
839	    /// thread::spawn(move || {
840	    ///     thread::sleep(Duration::from_secs(1));
841	    ///     s1.send(10).unwrap();
842	    /// });
843	    /// # let t2 =
844	    /// thread::spawn(move || s2.send(20).unwrap());
845	    ///
846	    /// let mut sel = Select::new();
847	    /// let oper1 = sel.recv(&r1);
848	    /// let oper2 = sel.recv(&r2);
849	    ///
850	    /// // The second operation will be selected because it becomes ready first.
851	    /// let oper = sel.select();
852	    /// match oper.index() {
853	    ///     i if i == oper1 => assert_eq!(oper.recv(&r1), Ok(10)),
854	    ///     i if i == oper2 => assert_eq!(oper.recv(&r2), Ok(20)),
855	    ///     _ => unreachable!(),
856	    /// }
857	    /// # t1.join().unwrap(); // join thread to avoid https://github.com/rust-lang/miri/issues/1371
858	    /// # t2.join().unwrap(); // join thread to avoid https://github.com/rust-lang/miri/issues/1371
859	    /// ```
860	    pub fn select(&mut self) -> SelectedOperation<'a> {
861	        select(&mut self.handles, self.biased)
862	    }
