864	    /// Blocks for a limited time until one of the operations becomes ready and selects it.
865	    ///
866	    /// If an operation becomes ready, it is selected and returned. If multiple operations are
867	    /// ready at the same time, a random one among them is selected. If none of the operations
868	    /// become ready for the specified duration, an error is returned.
869	    ///
870	    /// An operation is considered to be ready if it doesn't have to block. Note that it is ready
871	    /// even when it will simply return an error because the channel is disconnected.
872	    ///
873	    /// The selected operation must be completed with [`SelectedOperation::send`]
874	    /// or [`SelectedOperation::recv`].
875	    ///
876	    /// # Examples
877	    ///
878	    /// ```
879	    /// use std::thread;
880	    /// use std::time::Duration;
881	    /// use crossbeam_channel::{unbounded, Select};
882	    ///
883	    /// let (s1, r1) = unbounded();
884	    /// let (s2, r2) = unbounded();
885	    ///
886	    /// # let t1 =
887	    /// thread::spawn(move || {
888	    ///     thread::sleep(Duration::from_secs(1));
889	    ///     s1.send(10).unwrap();
890	    /// });
891	    /// # let t2 =
892	    /// thread::spawn(move || s2.send(20).unwrap());
893	    ///
894	    /// let mut sel = Select::new();
895	    /// let oper1 = sel.recv(&r1);
896	    /// let oper2 = sel.recv(&r2);
897	    ///
898	    /// // The second operation will be selected because it becomes ready first.
899	    /// let oper = sel.select_timeout(Duration::from_millis(500));
900	    /// match oper {
901	    ///     Err(_) => panic!("should not have timed out"),
902	    ///     Ok(oper) => match oper.index() {
903	    ///         i if i == oper1 => assert_eq!(oper.recv(&r1), Ok(10)),
904	    ///         i if i == oper2 => assert_eq!(oper.recv(&r2), Ok(20)),
905	    ///         _ => unreachable!(),
906	    ///     }
