955	    /// let oper = sel.select_deadline(deadline);
956	    /// match oper {
957	    ///     Err(_) => panic!("should not have timed out"),
958	    ///     Ok(oper) => match oper.index() {
959	    ///         i if i == oper1 => assert_eq!(oper.recv(&r1), Ok(10)),
960	    ///         i if i == oper2 => assert_eq!(oper.recv(&r2), Ok(20)),
961	    ///         _ => unreachable!(),
962	    ///     }
963	    /// }
964	    /// # t1.join().unwrap(); // join thread to avoid https://github.com/rust-lang/miri/issues/1371
965	    /// # t2.join().unwrap(); // join thread to avoid https://github.com/rust-lang/miri/issues/1371
966	    /// ```
