1001	    /// // Both operations are initially ready, so a random one will be chosen.
1002	    /// match sel.try_ready() {
1003	    ///     Err(_) => panic!("both operations should be ready"),
1004	    ///     Ok(i) if i == oper1 => assert_eq!(r1.try_recv(), Ok(10)),
1005	    ///     Ok(i) if i == oper2 => assert_eq!(r2.try_recv(), Ok(20)),
1006	    ///     Ok(_) => unreachable!(),
1007	    /// }
