1053	    /// // The second operation will be selected because it becomes ready first.
1054	    /// match sel.ready() {
1055	    ///     i if i == oper1 => assert_eq!(r1.try_recv(), Ok(10)),
1056	    ///     i if i == oper2 => assert_eq!(r2.try_recv(), Ok(20)),
1057	    ///     _ => unreachable!(),
1058	    /// }
1059	    /// # t1.join().unwrap(); // join thread to avoid https://github.com/rust-lang/miri/issues/1371
1060	    /// # t2.join().unwrap(); // join thread to avoid https://github.com/rust-lang/miri/issues/1371
1061	    /// ```
