1197	/// A selected operation that needs to be completed.
1198	///
1199	/// To complete the operation, call [`send`] or [`recv`].
1200	///
1201	/// # Panics
1202	///
1203	/// Forgetting to complete the operation is an error and might lead to deadlocks. If a
1204	/// `SelectedOperation` is dropped without completion, a panic occurs.
1205	///
1206	/// [`send`]: SelectedOperation::send
1207	/// [`recv`]: SelectedOperation::recv
1208	#[must_use]
1209	pub struct SelectedOperation<'a> {
1210	    /// Token needed to complete the operation.
1211	    token: Token,
1212	
1213	    /// The index of the selected operation.
1214	    index: usize,
1215	
1216	    /// The address of the selected `Sender` or `Receiver`.
1217	    addr: usize,
1218	
1219	    /// Indicates that `Sender`s and `Receiver`s are borrowed.
1220	    _marker: PhantomData<&'a ()>,
1221	}
