1223	impl SelectedOperation<'_> {
1224	    /// Returns the index of the selected operation.
1225	    ///
1226	    /// # Examples
1227	    ///
1228	    /// ```
1229	    /// use crossbeam_channel::{bounded, Select};
1230	    ///
1231	    /// let (s1, r1) = bounded::<()>(0);
1232	    /// let (s2, r2) = bounded::<()>(0);
1233	    /// let (s3, r3) = bounded::<()>(1);
1234	    ///
1235	    /// let mut sel = Select::new();
1236	    /// let oper1 = sel.send(&s1);
1237	    /// let oper2 = sel.recv(&r2);
1238	    /// let oper3 = sel.send(&s3);
1239	    ///
1240	    /// // Only the last operation is ready.
1241	    /// let oper = sel.select();
1242	    /// assert_eq!(oper.index(), 2);
1243	    /// assert_eq!(oper.index(), oper3);
1244	    ///
1245	    /// // Complete the operation.
1246	    /// oper.send(&s3, ()).unwrap();
1247	    /// ```
1248	    pub fn index(&self) -> usize {
