1252	    /// Completes the send operation.
1253	    ///
1254	    /// The passed [`Sender`] reference must be the same one that was used in [`Select::send`]
1255	    /// when the operation was added.
1256	    ///
1257	    /// # Panics
1258	    ///
1259	    /// Panics if an incorrect [`Sender`] reference is passed.
1260	    ///
1261	    /// # Examples
1262	    ///
1263	    /// ```
1264	    /// use crossbeam_channel::{bounded, Select, SendError};
1265	    ///
1266	    /// let (s, r) = bounded::<i32>(0);
1267	    /// drop(r);
1268	    ///
1269	    /// let mut sel = Select::new();
1270	    /// let oper1 = sel.send(&s);
1271	    ///
1272	    /// let oper = sel.select();
1273	    /// assert_eq!(oper.index(), oper1);
1274	    /// assert_eq!(oper.send(&s, 10), Err(SendError(10)));
