1276	    pub fn send<T>(mut self, s: &Sender<T>, msg: T) -> Result<(), SendError<T>> {
1277	        assert!(
1278	            s.addr() == self.addr,
1279	            "passed a sender that wasn't selected",
1280	        );
1281	        let res = unsafe { channel::write(s, &mut self.token, msg) };
1282	        mem::forget(self);
1283	        res.map_err(SendError)
1284	    }
