1290	    ///
1291	    /// # Panics
1292	    ///
1293	    /// Panics if an incorrect [`Receiver`] reference is passed.
1294	    ///
1295	    /// # Examples
1296	    ///
1297	    /// ```
1298	    /// use crossbeam_channel::{bounded, Select, RecvError};
1299	    ///
1300	    /// let (s, r) = bounded::<i32>(0);
1301	    /// drop(s);
1302	    ///
1303	    /// let mut sel = Select::new();
1304	    /// let oper1 = sel.recv(&r);
1305	    ///
1306	    /// let oper = sel.select();
1307	    /// assert_eq!(oper.index(), oper1);
1308	    /// assert_eq!(oper.recv(&r), Err(RecvError));
1309	    /// ```
1310	    pub fn recv<T>(mut self, r: &Receiver<T>) -> Result<T, RecvError> {
1311	        assert!(
1312	            r.addr() == self.addr,
1313	            "passed a receiver that wasn't selected",
1314	        );
1315	        let res = unsafe { channel::read(r, &mut self.token) };
1316	        mem::forget(self);
1317	        res.map_err(|_| RecvError)
1318	    }
1319	}
