1	//! Thread-local context used in select.
2	
3	use alloc::sync::Arc;
4	use core::{
5	    cell::Cell,
6	    ptr,
7	    sync::atomic::{AtomicPtr, AtomicUsize, Ordering},
8	};
9	use std::{
10	    thread::{self, Thread, ThreadId},
11	    time::Instant,
12	};
13	
14	use crossbeam_utils::Backoff;
15	
16	use crate::select::Selected;
17	
18	/// Thread-local context used in select.
19	// This is a private API that is used by the select macro.
20	#[derive(Debug, Clone)]
21	pub struct Context {
22	    inner: Arc<Inner>,
23	}
24	
25	/// Inner representation of `Context`.
26	#[derive(Debug)]
27	struct Inner {
28	    /// Selected operation.
29	    select: AtomicUsize,
30	
31	    /// A slot into which another thread may store a pointer to its `Packet`.
32	    packet: AtomicPtr<()>,
33	
34	    /// Thread handle.
35	    thread: Thread,
36	
37	    /// Thread id.
38	    thread_id: ThreadId,
39	}
40	
41	impl Context {
42	    /// Creates a new context for the duration of the closure.
43	    #[inline]
44	    pub fn with<F, R>(f: F) -> R
45	    where
46	        F: FnOnce(&Self) -> R,
47	    {
48	        std::thread_local! {
49	            /// Cached thread-local context.
50	            static CONTEXT: Cell<Option<Context>> = Cell::new(Some(Context::new()));
51	        }
52	
53	        let mut f = Some(f);
54	        let mut f = |cx: &Self| -> R {
55	            let f = f.take().unwrap();
56	            f(cx)
57	        };
58	
59	        CONTEXT
60	            .try_with(|cell| match cell.take() {
61	                None => f(&Self::new()),
62	                Some(cx) => {
63	                    cx.reset();
64	                    let res = f(&cx);
65	                    cell.set(Some(cx));
66	                    res
67	                }
68	            })
69	            .unwrap_or_else(|_| f(&Self::new()))
70	    }
71	
72	    /// Creates a new `Context`.
73	    #[cold]
74	    fn new() -> Self {
75	        Self {
76	            inner: Arc::new(Inner {
77	                select: AtomicUsize::new(Selected::Waiting.into()),
78	                packet: AtomicPtr::new(ptr::null_mut()),
79	                thread: thread::current(),
80	                thread_id: thread::current().id(),
81	            }),
82	        }
83	    }
84	
85	    /// Resets `select` and `packet`.
86	    #[inline]
87	    fn reset(&self) {
88	        self.inner
89	            .select
90	            .store(Selected::Waiting.into(), Ordering::Release);
91	        self.inner.packet.store(ptr::null_mut(), Ordering::Release);
92	    }
93	
94	    /// Attempts to select an operation.
95	    ///
96	    /// On failure, the previously selected operation is returned.
97	    #[inline]
98	    pub fn try_select(&self, select: Selected) -> Result<(), Selected> {
99	        self.inner
100	            .select
101	            .compare_exchange(
102	                Selected::Waiting.into(),
103	                select.into(),
104	                Ordering::AcqRel,
105	                Ordering::Acquire,
106	            )
107	            .map(|_| ())
108	            .map_err(|e| e.into())
109	    }
110	
111	    /// Returns the selected operation.
112	    #[inline]
113	    pub fn selected(&self) -> Selected {
114	        Selected::from(self.inner.select.load(Ordering::Acquire))
115	    }
116	
117	    /// Stores a packet.
118	    ///
119	    /// This method must be called after `try_select` succeeds and there is a packet to provide.
120	    #[inline]
121	    pub fn store_packet(&self, packet: *mut ()) {
122	        if !packet.is_null() {
123	            self.inner.packet.store(packet, Ordering::Release);
124	        }
125	    }
126	
127	    /// Waits until a packet is provided and returns it.
128	    #[inline]
129	    pub fn wait_packet(&self) -> *mut () {
130	        let backoff = Backoff::new();
131	        loop {
132	            let packet = self.inner.packet.load(Ordering::Acquire);
133	            if !packet.is_null() {
134	                return packet;
135	            }
136	            backoff.snooze();
137	        }
138	    }
139	
140	    /// Waits until an operation is selected and returns it.
141	    ///
142	    /// If the deadline is reached, `Selected::Aborted` will be selected.
143	    #[inline]
144	    pub fn wait_until(&self, deadline: Option<Instant>) -> Selected {
145	        loop {
146	            // Check whether an operation has been selected.
147	            let sel = Selected::from(self.inner.select.load(Ordering::Acquire));
148	            if sel != Selected::Waiting {
149	                return sel;
150	            }
151	
152	            // If there's a deadline, park the current thread until the deadline is reached.
153	            if let Some(end) = deadline {
154	                let now = Instant::now();
155	
156	                if now < end {
157	                    thread::park_timeout(end - now);
158	                } else {
159	                    // The deadline has been reached. Try aborting select.
160	                    return match self.try_select(Selected::Aborted) {
161	                        Ok(()) => Selected::Aborted,
162	                        Err(s) => s,
163	                    };
164	                }
165	            } else {
166	                thread::park();
167	            }
168	        }
169	    }
170	
171	    /// Unparks the thread this context belongs to.
172	    #[inline]
173	    pub fn unpark(&self) {
174	        self.inner.thread.unpark();
175	    }
176	
177	    /// Returns the id of the thread this context belongs to.
178	    #[inline]
179	    pub fn thread_id(&self) -> ThreadId {
180	        self.inner.thread_id
181	    }
182	}
