4	use core::{
5	    ops,
6	    ptr::NonNull,
7	    sync::atomic::{AtomicBool, AtomicUsize, Ordering},
8	};
9	use std::process;
10	
11	/// Reference counter internals.
12	struct Counter<C> {
13	    /// The number of senders associated with the channel.
14	    senders: AtomicUsize,
15	
16	    /// The number of receivers associated with the channel.
17	    receivers: AtomicUsize,
18	
19	    /// Set to `true` if the last sender or the last receiver reference deallocates the channel.
20	    destroy: AtomicBool,
21	
22	    /// The internal channel.
23	    chan: C,
24	}
25	
26	/// Wraps a channel into the reference counter.
27	pub(crate) fn new<C>(chan: C) -> (Sender<C>, Receiver<C>) {
28	    let counter = NonNull::from(Box::leak(Box::new(Counter {
29	        senders: AtomicUsize::new(1),
30	        receivers: AtomicUsize::new(1),
31	        destroy: AtomicBool::new(false),
32	        chan,
33	    })));
34	    let s = Sender { counter };
35	    let r = Receiver { counter };
36	    (s, r)
37	}
38	
39	/// The sending side.
40	pub(crate) struct Sender<C> {
41	    counter: NonNull<Counter<C>>,
42	}
43	
44	impl<C> Sender<C> {
45	    /// Returns the internal `Counter`.
46	    fn counter(&self) -> &Counter<C> {
47	        unsafe { self.counter.as_ref() }
48	    }
49	
50	    /// Acquires another sender reference.
51	    pub(crate) fn acquire(&self) -> Self {
52	        let count = self.counter().senders.fetch_add(1, Ordering::Relaxed);
53	
54	        // Cloning senders and calling `mem::forget` on the clones could potentially overflow the
55	        // counter. It's very difficult to recover sensibly from such degenerate scenarios so we
56	        // just abort when the count becomes very large.
57	        if count > isize::MAX as usize {
58	            process::abort();
59	        }
60	
61	        Self {
62	            counter: self.counter,
63	        }
64	    }
65	
66	    /// Releases the sender reference.
67	    ///
68	    /// Function `disconnect` will be called if this is the last sender reference.
69	    pub(crate) unsafe fn release<F: FnOnce(&C) -> bool>(&self, disconnect: F) {
70	        if self.counter().senders.fetch_sub(1, Ordering::AcqRel) == 1 {
71	            disconnect(&self.counter().chan);
72	
73	            if self.counter().destroy.swap(true, Ordering::AcqRel) {
74	                drop(unsafe { Box::from_raw(self.counter.as_ptr()) });
75	            }
76	        }
77	    }
78	
79	    pub(crate) fn addr(&self) -> usize {
80	        self.counter.as_ptr() as usize
81	    }
82	}
83	
84	impl<C> ops::Deref for Sender<C> {
85	    type Target = C;
86	
87	    fn deref(&self) -> &C {
88	        &self.counter().chan
89	    }
90	}
91	
92	impl<C> PartialEq for Sender<C> {
93	    fn eq(&self, other: &Self) -> bool {
94	        self.counter == other.counter
95	    }
96	}
97	
98	/// The receiving side.
99	pub(crate) struct Receiver<C> {
100	    counter: NonNull<Counter<C>>,
101	}
102	
103	impl<C> Receiver<C> {
104	    /// Returns the internal `Counter`.
105	    fn counter(&self) -> &Counter<C> {
106	        unsafe { self.counter.as_ref() }
107	    }
108	
109	    /// Acquires another receiver reference.
110	    pub(crate) fn acquire(&self) -> Self {
111	        let count = self.counter().receivers.fetch_add(1, Ordering::Relaxed);
112	
113	        // Cloning receivers and calling `mem::forget` on the clones could potentially overflow the
114	        // counter. It's very difficult to recover sensibly from such degenerate scenarios so we
115	        // just abort when the count becomes very large.
116	        if count > isize::MAX as usize {
117	            process::abort();
118	        }
119	
120	        Self {
121	            counter: self.counter,
122	        }
123	    }
124	
125	    /// Releases the receiver reference.
126	    ///
127	    /// Function `disconnect` will be called if this is the last receiver reference.
128	    pub(crate) unsafe fn release<F: FnOnce(&C) -> bool>(&self, disconnect: F) {
129	        if self.counter().receivers.fetch_sub(1, Ordering::AcqRel) == 1 {
130	            disconnect(&self.counter().chan);
131	
132	            if self.counter().destroy.swap(true, Ordering::AcqRel) {
133	                drop(unsafe { Box::from_raw(self.counter.as_ptr()) });
134	            }
135	        }
136	    }
137	
138	    pub(crate) fn addr(&self) -> usize {
139	        self.counter.as_ptr() as usize
140	    }
141	}
142	
143	impl<C> ops::Deref for Receiver<C> {
144	    type Target = C;
145	
146	    fn deref(&self) -> &C {
147	        &self.counter().chan
148	    }
149	}
150	
151	impl<C> PartialEq for Receiver<C> {
152	    fn eq(&self, other: &Self) -> bool {
153	        self.counter == other.counter
154	    }
155	}
